}

class AWSHttpRequest {
  final Uri uri;
  final String method;
  final Map<String, String> headers;
  final List<int> body;

  AWSHttpRequest._(this.method, this.uri, this.headers, this.body);

  factory AWSHttpRequest.put(
    Uri uri, {
    required Map<String, String> headers,
    required List<int> body,
  }) {
    return AWSHttpRequest._('PUT', uri, headers, body);
  }
}

class AWSCredentialScope {
  final String region;
  final AWSService service;
  const AWSCredentialScope({required this.region, required this.service});
}

class AWSService {
