class AWSSigV4Signer {
  final AWSCredentialsProvider credentialsProvider;
  const AWSSigV4Signer({required this.credentialsProvider});

  Future<AWSHttpRequest> sign(
    AWSHttpRequest request, {
    required AWSCredentialScope credentialScope,
  }) async {
    final credentials = await credentialsProvider.getAwsCredentials();
    final now = DateTime.now().toUtc();
    final amzDate = _formatAmzDate(now);
    final dateStamp = _formatDateStamp(now);

    final headers = <String, String>{
      ...request.headers.map((k, v) => MapEntry(k.toLowerCase(), v.trim())),
      'x-amz-date': amzDate,
    };

    final payloadHash = sha256.convert(request.body).toString();
    headers['x-amz-content-sha256'] = payloadHash;

    final canonicalUri = request.uri.path.isEmpty ? '/' : request.uri.path;
    final canonicalQueryString = request.uri.query;
    final sortedHeaders = headers.entries.toList()
      ..sort((a, b) => a.key.compareTo(b.key));

    final canonicalHeaders = StringBuffer();
    final signedHeaders = sortedHeaders.map((e) => e.key).join(';');
    for (final entry in sortedHeaders) {
      canonicalHeaders.writeln('${entry.key}:${entry.value}');
    }

    final canonicalRequest = [
      request.method,
      canonicalUri,
      canonicalQueryString,
      canonicalHeaders.toString(),
      signedHeaders,
      payloadHash,
    ].join('\n');

    final scope = '$dateStamp/${credentialScope.region}/${credentialScope.service.value}/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      scope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final kDate = _sign(utf8.encode('AWS4${credentials.secretAccessKey}'), dateStamp);
    final kRegion = _sign(kDate, credentialScope.region);
    final kService = _sign(kRegion, credentialScope.service.value);
    final kSigning = _sign(kService, 'aws4_request');
    final signature = Hmac(sha256, kSigning).convert(utf8.encode(stringToSign)).toString();

    headers['authorization'] =
        'AWS4-HMAC-SHA256 Credential=${credentials.accessKeyId}/$scope, SignedHeaders=$signedHeaders, Signature=$signature';

    return AWSHttpRequest._(request.method, request.uri, headers, request.body);
  }

  List<int> _sign(List<int> key, String msg) {
    return Hmac(sha256, key).convert(utf8.encode(msg)).bytes;
  }

  String _formatAmzDate(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}T${two(dt.hour)}${two(dt.minute)}${two(dt.second)}Z';
  }

  String _formatDateStamp(DateTime dt) {
    String two(int v) => v.toString().padLeft(2, '0');
    return '${dt.year}${two(dt.month)}${two(dt.day)}';
  }
}